import{_ as a,o,c as r,a0 as s}from"./chunks/framework.BjpW4enL.js";const g=JSON.parse('{"title":"Workflow Guidelines","description":"","frontmatter":{},"headers":[],"relativePath":"40_Operacoes/guides/workflow.md","filePath":"40_Operacoes/guides/workflow.md","lastUpdated":1783623176000}'),t={name:"40_Operacoes/guides/workflow.md"};function i(n,e,l,d,c,u){return o(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="workflow-guidelines" tabindex="-1">Workflow Guidelines <a class="header-anchor" href="#workflow-guidelines" aria-label="Permalink to &quot;Workflow Guidelines&quot;">​</a></h1><h2 id="plan-first" tabindex="-1">Plan-First <a class="header-anchor" href="#plan-first" aria-label="Permalink to &quot;Plan-First&quot;">​</a></h2><p>Antes de qualquer implementação com 2+ passos, <strong>planeje primeiro</strong>.</p><h3 id="regras" tabindex="-1">Regras <a class="header-anchor" href="#regras" aria-label="Permalink to &quot;Regras&quot;">​</a></h3><ol><li><strong>Multi-step task → plano antes de código</strong>. Escreva o plano (mental ou arquivo) antes do primeiro grep.</li><li><strong>Um plano define ONDE (arquivos), O QUÊ (mudanças) e COMO (sequência)</strong>.</li><li><strong>Plano aprovado → execução linear</strong>. Não mude o plano no meio sem revalidar.</li><li><strong>Planos são baratos, grep-edit loops são caros</strong>. Invista 30s em planejar, economize 5min de retrabalho.</li></ol><h2 id="contextos-descartaveis-—-subagentes-para-trabalho-mecanico" tabindex="-1">Contextos Descartáveis — Subagentes para Trabalho Mecânico <a class="header-anchor" href="#contextos-descartaveis-—-subagentes-para-trabalho-mecanico" aria-label="Permalink to &quot;Contextos Descartáveis — Subagentes para Trabalho Mecânico&quot;">​</a></h2><h3 id="principio" tabindex="-1">Princípio <a class="header-anchor" href="#principio" aria-label="Permalink to &quot;Princípio&quot;">​</a></h3><p>O contexto do agente principal é o recurso mais valioso do sistema. <strong>Tudo que pode ser delegado, deve ser delegado.</strong></p><h3 id="regras-1" tabindex="-1">Regras <a class="header-anchor" href="#regras-1" aria-label="Permalink to &quot;Regras&quot;">​</a></h3><ol><li><strong>Trabalho mecânico → subagente</strong>: commits, testes repetitivos, documentação padrão, configuração de ferramentas</li><li><strong>Decisão → agente principal</strong>: arquitetura, design, validação de resultados, comunicação com o usuário</li><li><strong>Exploração → subagente async</strong>: <code>explore</code>/<code>librarian</code> em background, coletar resultados via <code>&lt;system-reminder&gt;</code></li><li><strong>Contexto do subagente é volátil</strong>: não confiar que ele &quot;lembra&quot; — passar instruções completas a cada chamada</li><li><strong>Use <code>task(task_id=&quot;ses_...&quot;)</code> para continuar sessões</strong>: preserva o contexto do subagente entre chamadas</li></ol>',10)])])}const m=a(t,[["render",i]]);export{g as __pageData,m as default};
